package com.example.oidcdemo.service;

import com.example.oidcdemo.model.CustomOidcUser;
import com.example.oidcdemo.model.UserSession;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.security.core.GrantedAuthority;
import org.springframework.security.core.authority.SimpleGrantedAuthority;
import org.springframework.security.oauth2.client.oidc.userinfo.OidcUserRequest;
import org.springframework.security.oauth2.client.oidc.userinfo.OidcUserService;
import org.springframework.security.oauth2.core.OAuth2AuthenticationException;
import org.springframework.security.oauth2.core.oidc.OidcIdToken;
import org.springframework.security.oauth2.core.oidc.user.OidcUser;
import org.springframework.stereotype.Service;

import java.time.Instant;
import java.util.*;
import java.util.stream.Collectors;

@Service
public class CustomOidcUserService extends OidcUserService {

    private static final Logger logger = LoggerFactory.getLogger(CustomOidcUserService.class);

    private final IdTokenClaimsParser idTokenClaimsParser;
    private final UserSessionManager userSessionManager;

    public CustomOidcUserService(IdTokenClaimsParser idTokenClaimsParser,
                                  UserSessionManager userSessionManager) {
        this.idTokenClaimsParser = idTokenClaimsParser;
        this.userSessionManager = userSessionManager;
    }

    @Override
    public OidcUser loadUser(OidcUserRequest userRequest) throws OAuth2AuthenticationException {
        OidcUser oidcUser = super.loadUser(userRequest);

        logger.info("Loading OIDC user: {}", oidcUser.getSubject());

        // Parse ID token claims
        OidcIdToken idToken = userRequest.getIdToken();
        UserSession userSession = idTokenClaimsParser.parseIdTokenClaims(idToken);

        // Set tokens
        userSession.setAccessToken(userRequest.getAccessToken().getTokenValue());
        userSession.setIdToken(idToken.getTokenValue());
        userSession.setTokenExpiration(userRequest.getAccessToken().getExpiresAt());

        // Extract roles from claims
        Set<String> roles = extractRoles(idToken.getClaims());
        userSession.setRoles(roles);

        // Store additional claims
        Map<String, Object> additionalClaims = new HashMap<>(oidcUser.getClaims());
        userSession.setAdditionalClaims(additionalClaims);

        // Build authorities
        Set<GrantedAuthority> authorities = new HashSet<>(oidcUser.getAuthorities());
        roles.forEach(role -> authorities.add(new SimpleGrantedAuthority("ROLE_" + role.toUpperCase())));

        // Store user session
        userSessionManager.createSession(userSession);

        logger.info("User session created for: {} ({})", userSession.getName(), userSession.getEmail());

        return new CustomOidcUser(authorities, idToken, oidcUser.getUserInfo(), userSession);
    }

    @SuppressWarnings("unchecked")
    private Set<String> extractRoles(Map<String, Object> claims) {
        Set<String> roles = new HashSet<>();
        roles.add("USER"); // Default role

        // Try to extract roles from various claim formats
        Object rolesClaim = claims.get("roles");
        if (rolesClaim instanceof Collection) {
            roles.addAll(((Collection<String>) rolesClaim));
        }

        // Check realm_access for Keycloak-style claims
        Object realmAccess = claims.get("realm_access");
        if (realmAccess instanceof Map) {
            Object realmRoles = ((Map<String, Object>) realmAccess).get("roles");
            if (realmRoles instanceof Collection) {
                roles.addAll(((Collection<String>) realmRoles));
            }
        }

        // Check groups claim
        Object groupsClaim = claims.get("groups");
        if (groupsClaim instanceof Collection) {
            ((Collection<String>) groupsClaim).forEach(group -> {
                if (group.startsWith("/")) {
                    roles.add(group.substring(1).toUpperCase());
                } else {
                    roles.add(group.toUpperCase());
                }
            });
        }

        return roles;
    }
}

// ==================== ID Token Claims Parser ====================
package com.example.oidcdemo.service;

import com.example.oidcdemo.model.UserSession;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.security.oauth2.core.oidc.OidcIdToken;
import org.springframework.stereotype.Service;

import java.time.Instant;
import java.util.Map;

@Service
public class IdTokenClaimsParser {

    private static final Logger logger = LoggerFactory.getLogger(IdTokenClaimsParser.class);

    public UserSession parseIdTokenClaims(OidcIdToken idToken) {
        UserSession userSession = new UserSession();

        Map<String, Object> claims = idToken.getClaims();

        logger.debug("Parsing ID token claims: {}", claims.keySet());

        // Standard OIDC claims
        userSession.setSubject(getStringClaim(claims, "sub"));
        userSession.setEmail(getStringClaim(claims, "email"));
        userSession.setEmailVerified(getBooleanClaim(claims, "email_verified"));
        userSession.setName(getStringClaim(claims, "name"));
        userSession.setGivenName(getStringClaim(claims, "given_name"));
        userSession.setFamilyName(getStringClaim(claims, "family_name"));
        userSession.setPicture(getStringClaim(claims, "picture"));
        userSession.setLocale(getStringClaim(claims, "locale"));

        // If name is not set, construct from given_name and family_name
        if (userSession.getName() == null || userSession.getName().isEmpty()) {
            String constructedName = constructName(userSession.getGivenName(), userSession.getFamilyName());
            if (constructedName != null) {
                userSession.setName(constructedName);
            } else if (userSession.getEmail() != null) {
                userSession.setName(userSession.getEmail());
            } else {
                userSession.setName(userSession.getSubject());
            }
        }

        // Validate essential claims
        validateClaims(idToken);

        logger.info("Parsed ID token for subject: {}, email: {}", userSession.getSubject(), userSession.getEmail());

        return userSession;
    }

    private void validateClaims(OidcIdToken idToken) {
        // Check token expiration
        Instant expiresAt = idToken.getExpiresAt();
        if (expiresAt != null && Instant.now().isAfter(expiresAt)) {
            logger.warn("ID token has expired at: {}", expiresAt);
            throw new IllegalStateException("ID token has expired");
        }

        // Check issued at (not too far in the past)
        Instant issuedAt = idToken.getIssuedAt();
        if (issuedAt != null) {
            Instant maxAge = Instant.now().minusSeconds(86400); // 24 hours
            if (issuedAt.isBefore(maxAge)) {
                logger.warn("ID token was issued too long ago: {}", issuedAt);
                throw new IllegalStateException("ID token issued at time is too old");
            }
        }

        // Ensure subject is present
        if (idToken.getSubject() == null || idToken.getSubject().isEmpty()) {
            throw new IllegalStateException("ID token is missing subject claim");
        }
    }

    private String getStringClaim(Map<String, Object> claims, String claimName) {
        Object value = claims.get(claimName);
        return value != null ? value.toString() : null;
    }

    private boolean getBooleanClaim(Map<String, Object> claims, String claimName) {
        Object value = claims.get(claimName);
        if (value instanceof Boolean) {
            return (Boolean) value;
        }
        if (value instanceof String) {
            return Boolean.parseBoolean((String) value);
        }
        return false;
    }

    private String constructName(String givenName, String familyName) {
        StringBuilder name = new StringBuilder();
        if (givenName != null && !givenName.isEmpty()) {
            name.append(givenName);
        }
        if (familyName != null && !familyName.isEmpty()) {
            if (name.length() > 0) {
                name.append(" ");
            }
            name.append(familyName);
        }
        return name.length() > 0 ? name.toString() : null;
    }
}

// ==================== Token Exchange Service ====================
package com.example.oidcdemo.service;

import com.example.oidcdemo.config.OidcProviderConfig;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.http.*;
import org.springframework.stereotype.Service;
import org.springframework.util.LinkedMultiValueMap;
import org.springframework.util.MultiValueMap;
import org.springframework.web.client.RestTemplate;

import java.util.Map;

@Service
public class TokenExchangeService {

    private static final Logger logger = LoggerFactory.getLogger(TokenExchangeService.class);

    private final RestTemplate restTemplate;
    private final OidcProviderConfig oidcProviderConfig;

    @Value("${spring.security.oauth2.client.registration.oidc-provider.client-id}")
    private String clientId;

    @Value("${spring.security.oauth2.client.registration.oidc-provider.client-secret}")
    private String clientSecret;

    @Value("${app.base-url:http://localhost:8080}")
    private String baseUrl;

    public TokenExchangeService(RestTemplate restTemplate, OidcProviderConfig oidcProviderConfig) {
        this.restTemplate = restTemplate;
        this.oidcProviderConfig = oidcProviderConfig;
    }

    /**
     * Exchange authorization code for tokens at the token endpoint.
     */
    @SuppressWarnings("unchecked")
    public Map<String, Object> exchangeAuthorizationCode(String authorizationCode) {
        logger.info("Exchanging authorization code for tokens");

        HttpHeaders headers = new HttpHeaders();
        headers.setContentType(MediaType.APPLICATION_FORM_URLENCODED);

        MultiValueMap<String, String> body = new LinkedMultiValueMap<>();
        body.add("grant_type", "authorization_code");
        body.add("code", authorizationCode);
        body.add("redirect_uri", baseUrl + "/login/oauth2/code/oidc-provider");
        body.add("client_id", clientId);
        body.add("client_secret", clientSecret);

        HttpEntity<MultiValueMap<String, String>> request = new HttpEntity<>(body, headers);

        try {
            ResponseEntity<Map> response = restTemplate.exchange(
                    oidcProviderConfig.getTokenUri(),
                    HttpMethod.POST,
                    request,
                    Map.class
            );

            if (response.getStatusCode() == HttpStatus.OK && response.getBody() != null) {
                logger.info("Successfully exchanged authorization code for tokens");
                return response.getBody();
            } else {
                logger.error("Token exchange failed with status: {}", response.getStatusCode());
                throw new RuntimeException("Token exchange failed");
            }
        } catch (Exception e) {
            logger.error("Error during token exchange: {}", e.getMessage(), e);
            throw new RuntimeException("Failed to exchange authorization code", e);
        }
    }

    /**
     * Refresh an access token using a refresh token.
     */
    @SuppressWarnings("unchecked")
    public Map<String, Object> refreshToken(String refreshToken) {
        logger.info("Refreshing access token");

        HttpHeaders headers = new HttpHeaders();
        headers.setContentType(MediaType.APPLICATION_FORM_URLENCODED);

        MultiValueMap<String, String> body = new LinkedMultiValueMap<>();
        body.add("grant_type", "refresh_token");
        body.add("refresh_token", refreshToken);
        body.add("client_id", clientId);
        body.add("client_secret", clientSecret);

        HttpEntity<MultiValueMap<String, String>> request = new HttpEntity<>(body, headers);

        try {
            ResponseEntity<Map> response = restTemplate.exchange(
                    oidcProviderConfig.getTokenUri(),
                    HttpMethod.POST,
                    request,
                    Map.class
            );

            if (response.getStatusCode() == HttpStatus.OK && response.getBody() != null) {
                logger.info("Successfully refreshed access token");
                return response.getBody();
            } else {
                logger.error("Token refresh failed with status: {}", response.getStatusCode());
                throw new RuntimeException("Token refresh failed");
            }
        } catch (Exception e) {
            logger.error("Error during token refresh: {}", e.getMessage(), e);
            throw new RuntimeException("Failed to refresh token", e);
        }
    }

    /**
     * Fetch user info from the userinfo endpoint.
     */
    @SuppressWarnings("unchecked")
    public Map<String, Object> fetchUserInfo(String accessToken) {
        logger.info("Fetching user info from userinfo endpoint");

        HttpHeaders headers = new HttpHeaders();
        headers.setBearerAuth(accessToken);

        HttpEntity<Void> request = new HttpEntity<>(headers);

        try {
            ResponseEntity<Map> response = restTemplate.exchange(
                    oidcProviderConfig.getUserInfoUri(),
                    HttpMethod.GET,
                    request,
                    Map.class
            );

            if (response.getStatusCode() == HttpStatus.OK && response.getBody() != null) {
                logger.info("Successfully fetched user info");
                return response.getBody();
            } else {
                logger.error("UserInfo fetch failed with status: {}", response.getStatusCode());
                throw new RuntimeException("UserInfo fetch failed");
            }
        } catch (Exception e) {
            logger.error("Error fetching user info: {}", e.getMessage(), e);
            throw new RuntimeException("Failed to fetch user info", e);
        }
    }
}

// ==================== User Session Manager ====================
package com.example.oidcdemo.service;

import com.example.oidcdemo.model.UserSession;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.stereotype.Service;

import java.util.Map;
import java.util.Optional;
import java.util.concurrent.ConcurrentHashMap;

@Service
public class UserSessionManager {

    private static final Logger logger = LoggerFactory.getLogger(UserSessionManager.class);

    private final Map<String, UserSession> sessions = new ConcurrentHashMap<>();

    public void createSession(UserSession userSession) {
        sessions.put(userSession.getSubject(), userSession);
        logger.info("Session created for user: {} ({})", userSession.getName(), userSession.getSubject());
    }

    public Optional<UserSession> getSession(String subject) {
        return Optional.ofNullable(sessions.get(subject));
    }

    public void updateSession(UserSession userSession) {
        sessions.put(userSession.getSubject(), userSession);
        logger.info("Session updated for user: {}", userSession.getSubject());
    }

    public void removeSession(String subject) {
        sessions.remove(subject);
        logger.info("Session removed for user: {}", subject);
    }

    public boolean hasValidSession(String subject) {
        return getSession(subject)
                .map(session -> !session.isTokenExpired())
                .orElse(false);
    }

    public int getActiveSessionCount() {
        return sessions.size();
    }
}

// ==================== Authentication Success Handler ====================
package com.example.oidcdemo.handler;

import com.example.oidcdemo.model.CustomOidcUser;
import jakarta.servlet.ServletException;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpServletResponse;
import jakarta.servlet.http.HttpSession;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.security.core.Authentication;
import org.springframework.security.web.authentication.AuthenticationSuccessHandler;
import org.springframework.stereotype.Component;

import java.io.IOException;

@Component
public class OidcAuthenticationSuccessHandler implements AuthenticationSuccessHandler {

    private static final Logger logger = LoggerFactory.getLogger(OidcAuthenticationSuccessHandler.class);

    @Override
    public void onAuthenticationSuccess(HttpServletRequest request, HttpServletResponse response,
                                        Authentication authentication) throws IOException, ServletException {
        if (authentication.getPrincipal() instanceof CustomOidcUser) {
            CustomOidcUser oidcUser = (CustomOidcUser) authentication.getPrincipal();

            HttpSession session = request.getSession(true);
            session.setAttribute("userSession", oidcUser.getUserSession());
            session.setMaxInactiveInterval(3600); // 1 hour

            logger.info("Authentication successful for user: {} ({})",
                    oidcUser.getUserSession().getName(),
                    oidcUser.getUserSession().getEmail());
        }

        response.sendRedirect("/dashboard");
    }
}

