// ==================== Dashboard Controller ====================
package com.example.oidcdemo.controller;

import com.example.oidcdemo.model.CustomOidcUser;
import com.example.oidcdemo.model.UserSession;
import com.example.oidcdemo.service.UserSessionManager;
import org.springframework.security.core.annotation.AuthenticationPrincipal;
import org.springframework.security.oauth2.core.oidc.user.OidcUser;
import org.springframework.stereotype.Controller;
import org.springframework.ui.Model;
import org.springframework.web.bind.annotation.GetMapping;

@Controller
public class DashboardController {

    private final UserSessionManager userSessionManager;

    public DashboardController(UserSessionManager userSessionManager) {
        this.userSessionManager = userSessionManager;
    }

    @GetMapping("/dashboard")
    public String dashboard(@AuthenticationPrincipal OidcUser oidcUser, Model model) {
        if (oidcUser instanceof CustomOidcUser) {
            CustomOidcUser customUser = (CustomOidcUser) oidcUser;
            UserSession userSession = customUser.getUserSession();
            model.addAttribute("userSession", userSession);
            model.addAttribute("claims", oidcUser.getClaims());
        } else {
            model.addAttribute("name", oidcUser.getFullName());
            model.addAttribute("email", oidcUser.getEmail());
            model.addAttribute("claims", oidcUser.getClaims());
        }

        model.addAttribute("activeSessions", userSessionManager.getActiveSessionCount());

        return "dashboard";
    }
}

// ==================== User Info REST Controller ====================
package com.example.oidcdemo.controller;

import com.example.oidcdemo.model.CustomOidcUser;
import com.example.oidcdemo.model.UserSession;
import com.example.oidcdemo.service.TokenExchangeService;
import com.example.oidcdemo.service.UserSessionManager;
import org.springframework.http.ResponseEntity;
import org.springframework.security.core.annotation.AuthenticationPrincipal;
import org.springframework.security.oauth2.core.oidc.user.OidcUser;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RestController;

import java.util.HashMap;
import java.util.Map;

@RestController
@RequestMapping("/api")
public class UserInfoController {

    private final TokenExchangeService tokenExchangeService;
    private final UserSessionManager userSessionManager;

    public UserInfoController(TokenExchangeService tokenExchangeService,
                              UserSessionManager userSessionManager) {
        this.tokenExchangeService = tokenExchangeService;
        this.userSessionManager = userSessionManager;
    }

    @GetMapping("/userinfo")
    public ResponseEntity<Map<String, Object>> getUserInfo(@AuthenticationPrincipal OidcUser oidcUser) {
        Map<String, Object> userInfo = new HashMap<>();

        if (oidcUser instanceof CustomOidcUser) {
            CustomOidcUser customUser = (CustomOidcUser) oidcUser;
            UserSession session = customUser.getUserSession();

            userInfo.put("subject", session.getSubject());
            userInfo.put("name", session.getName());
            userInfo.put("email", session.getEmail());
            userInfo.put("emailVerified", session.isEmailVerified());
            userInfo.put("picture", session.getPicture());
            userInfo.put("roles", session.getRoles());
            userInfo.put("sessionCreatedAt", session.getSessionCreatedAt());
            userInfo.put("tokenExpired", session.isTokenExpired());
        } else {
            userInfo.put("name", oidcUser.getFullName());
            userInfo.put("email", oidcUser.getEmail());
            userInfo.put("claims", oidcUser.getClaims());
        }

        return ResponseEntity.ok(userInfo);
    }

    @GetMapping("/token/refresh")
    public ResponseEntity<Map<String, Object>> refreshToken(@AuthenticationPrincipal OidcUser oidcUser) {
        if (oidcUser instanceof CustomOidcUser) {
            CustomOidcUser customUser = (CustomOidcUser) oidcUser;
            UserSession session = customUser.getUserSession();

            if (session.getRefreshToken() != null) {
                Map<String, Object> tokenResponse = tokenExchangeService.refreshToken(session.getRefreshToken());

                // Update session with new tokens
                session.setAccessToken((String) tokenResponse.get("access_token"));
                if (tokenResponse.containsKey("refresh_token")) {
                    session.setRefreshToken((String) tokenResponse.get("refresh_token"));
                }

                userSessionManager.updateSession(session);

                Map<String, Object> result = new HashMap<>();
                result.put("message", "Token refreshed successfully");
                result.put("tokenExpired", session.isTokenExpired());
                return ResponseEntity.ok(result);
            }
        }

        return ResponseEntity.badRequest().body(Map.of("error", "No refresh token available"));
    }

    @GetMapping("/sessions/count")
    public ResponseEntity<Map<String, Object>> getSessionCount() {
        Map<String, Object> result = new HashMap<>();
        result.put("activeSessionCount", userSessionManager.getActiveSessionCount());
        return ResponseEntity.ok(result);
    }
}

